parameters.jsCode:
// We expect 3 items from the Merge node
// Each item has exactly one relevant field

let focus = "";
let keystoneHabits = "";
let userPrompt = "";
let systemPrompt = "";

for (const item of items) {
  if (item.json.focus) {
    focus = item.json.focus;
  }
  if (item.json.keystone_habits) {
    keystoneHabits = item.json.keystone_habits;
  }
  if (item.json.user_prompt) {
    userPrompt = item.json.user_prompt;
  }

  if (item.json.system_prompt){
    systemPrompt = item.json.system_prompt;
  }
}

// Build final prompt (NO {{ }} placeholders)
const finalPrompt =
  "Context:\n\n" +
  focus + "\n\n" +
  keystoneHabits + "\n\n" +
  userPrompt.replace(/Context:[\s\S]*?\n\n/, "");

return [
  {
    json: {
      user_prompt: finalPrompt,
      system_prompt: systemPrompt
    }
  }
];

let content = $input.first().json.daily_note

if (!content) {
  return [{
    json: {
      hasReflections: false,
      allCompleted: false,
      reflections: [],
      reflectionCount: 0,
    },
  }];
}

// Normalize line endings
content = content.replace(/\r\n/g, '\n');

// Split op Evening Review header (emoji maakt niet uit)
const parts = content.split(/## Morning Review.*\n/);

if (parts.length < 2) {
  return [{
    json: {
      hasReflections: false,
      allCompleted: false,
      reflections: [],
      reflectionCount: 0,
    },
  }];
}

// Pak alleen de Evening Review sectie
let eveningSection = parts[1];

// Stop bij volgende sectie als die bestaat
eveningSection = eveningSection.split('\n## ')[0];

// Match ALLE checklist items (checked en unchecked)
const taskRegex = /- \[( |x)\] (.+)/g;
const reflections = [];

let match;
while ((match = taskRegex.exec(eveningSection)) !== null) {
  reflections.push({
    text: match[2].trim(),
    completed: match[1] === 'x',
  });
}

const hasReflections = reflections.length > 0;
const allCompleted = hasReflections && reflections.every(r => r.completed);

return [{
  json: {
   hasReflections,
   allCompleted,
   reflections,
   reflectionCount: reflections.length,
  },
}];

// CORRECT: Eén array, één loop
const data = $input.first().json; // Top-level object met reflections array

if (data.hasReflections && data.reflections) {
  for (let reflection of data.reflections) {
    if (!reflection.completed) {
      return [{ json: { firstIncomplete: reflection.text } }];
    }
  }
}

return [{ json: { firstIncomplete: null } }];

// Parse the Cycle for: Goals, Tactics (bullet points), Lead Actions per goal
const cycleContent = items[0]?.json?.cycle_content || '';

// Check if we have valid content
if (!cycleContent || cycleContent.trim() === '' || cycleContent.includes('Error') || cycleContent.includes('not found')) {
  return [{
    json: {
      goals: [],
      error: 'Weekly plan file not found or empty'
    }
  }];
}

const goals = [];

// Split content by "## Goal X:" headers
const parts = cycleContent.split(/## Goal (\d+):\s*(.+?)\n/);

// Process pairs: [before, goalNum, goalTitle, content, before, goalNum2, ...]
for (let i = 1; i < parts.length; i += 3) {
  const goalNum = parseInt(parts[i]);
  const goalTitle = parts[i + 1].trim();
  let goalContent = parts[i + 2] || '';

  // Extract Tactics (now as bullet points with checkboxes)
  let tactics = [];
  const tacticsMatch = goalContent.match(/### Tactics\n([\s\S]*?)(?=### Lead Actions|$)/);

  if (tacticsMatch) {
    const tacticsText = tacticsMatch[1];
    // Find all lines starting with "- [ ]" or "- [x]"
    const tacticLines = tacticsText
      .split('\n')
      .filter(line => line.match(/^\s*-\s*\[[xX\s]\]/));

    tactics = tacticLines.map(line => {
      // Extract checkbox status and text
      const checkboxMatch = line.match(/^\s*-\s*\[([xX\s])\]\s*(.+)/);
      if (checkboxMatch) {
        const isChecked = checkboxMatch[1].toLowerCase() === 'x';
        const tacticText = checkboxMatch[2].trim();
        return {
          tactic: tacticText,
          checked: isChecked,
          icon: isChecked ? '✅' : '📌'
        };
      }
      return null;
    }).filter(t => t !== null);
  }

  // Extract Lead Actions
  let leadActions = [];
  const leadActionsMatch = goalContent.match(/### Lead Actions\n([\s\S]*?)(?=## Goal|# |$)/);

  if (leadActionsMatch) {
    leadActions = leadActionsMatch[1]
      .split('\n')
      .filter(line => line.trim().startsWith('-'))
      .map(line => line.trim());
  }

  goals.push({
    number: goalNum,
    title: goalTitle,
    tactics: tactics,
    leadActions: leadActions
  });
}

// Return error if no goals found
if (goals.length === 0) {
  return [{
    json: {
      goals: [],
      error: 'No goals found in weekly plan'
    }
  }];
}

return [{
  json: {
    goals: goals
  }
}];

// Extract tasks from the line below "Morgen:" in yesterday's note
const yesterdayNote = $input.first().json.yesterday_note || '';

let tasks = '';

// Match "Morgen:" line and capture the indented line below it
const morgenMatch = yesterdayNote.match(/- \[.\] \*\*Morgen:\*\*[^\n]*\n\s+(.+?)(?:\n|$)/);

if (morgenMatch && morgenMatch[1]) {
  tasks = morgenMatch[1].trim();
}

return [{
  json: {
    tasks: tasks  // Output as "tasks" for the next node
  }
}];

// Add tactic IDs to goals (1.1, 1.2, 2.1, 2.2, etc)
// Also pass through tomorrowPriority from yesterday's note
const goalsData = items[1]?.json || {};
const goals = goalsData.goals || [];
const error = goalsData.error || null;
const tomorrowPriority = items[2]?.json?.tomorrowPriority || '';

// Pass through error if present
if (error || !goals || !Array.isArray(goals) || goals.length === 0) {
  return [{
    json: {
      goals: [],
      tomorrowPriority: tomorrowPriority,
      error: error || 'No goals found',
      totalGoals: 0,
      totalTactics: 0
    }
  }];
}

// Add IDs to tactics
const goalsWithIds = goals.map(goal => {
  return {
    ...goal,
    tactics: (goal.tactics || []).map((tactic, index) => {
      const tacticNum = index + 1;
      const fullId = `${goal.number}.${tacticNum}`;

      return {
        ...tactic,
        id: fullId
      };
    })
  };
});

return [{
  json: {
    goals: goalsWithIds,
    tomorrowPriority: tomorrowPriority,
    totalGoals: goalsWithIds.length,
    totalTactics: goalsWithIds.reduce((sum, g) => sum + (g.tactics?.length || 0), 0)
  }
}];

// Build Goal Selection Menu with multi-select toggle support
const items = $input.all();
const chatId = ={{$node["CONFIG — Edit These Values"].json["telegramChatId"]}}; // Telegram chat ID

// Get goals from input
let goals = [];
for (const item of items) {
  if (item.json.goals && Array.isArray(item.json.goals)) {
    goals = item.json.goals;
    break;
  }
}

if (goals.length === 0) {
  return [{
    json: {
      error: true,
      errorMessage: 'No goals found in data',
      chatId: chatId
    }
  }];
}

// Build inline keyboard with toggle buttons
const inlineKeyboard = [];

goals.forEach((goal) => {
  const num = goal.number;
  // Start with unchecked state (first display)
  // The actual checked state will be managed via session storage
  inlineKeyboard.push([{
    text: `\u2610 ${num}\ufe0f\u20e3 ${goal.title.substring(0, 28)}`,
    callback_data: `goal_toggle_${num}`
  }]);
});

// Add confirm button
inlineKeyboard.push([{
  text: '\u2705 Bevestig selectie',
  callback_data: 'goals_confirm'
}]);

// Build message text
const messageText = `\ud83c\udfaf *Selecteer je goals voor vandaag*\n\n_Klik om te selecteren/deselecteren_\n_Klik "Bevestig selectie" wanneer je klaar bent_`;

return [{
  json: {
    error: false,
    chatId: chatId,
    messageText: messageText,
    replyMarkup: { inline_keyboard: inlineKeyboard },
    goals: goals,
    selectedGoals: [] // Start with empty selection
  }
}];

