const tasks = taskString
  .split(',')
  .map(task => task.trim())
  .filter(task => task.length > 0);

const formattedTasks = tasks
  .map(task => `- [ ] ${task}`)
  .join('\n');

const output = `### Today's Focus\n${formattedTasks}`;

return [{
  json: {
    focusSection: output,
    tasks: tasks,
    taskCount: tasks.length
  }
}];

const focus = $('Create Today\'s Focus').first().json.focusSection;
let dailyNote = $input.first().json.daily_note;

// Replace the template section with actual focus tasks
// Matches "### Today's Focus" followed by any lines containing {{focus_task...}}
dailyNote = dailyNote.replace(
  /### Today's Focus\n(?:- \[ \] \{\{focus_task\d+\}\}\n?)+/,
  focus + '\n'
);

return [{ json: { updatedDailyNote: dailyNote } }];

const goals = $('Add Tactic IDs (1.1, 1.2, etc)').first().json.goals;

const combinedLeadActions = [];

for (const goal of goals) {
  if (Array.isArray(goal.leadActions)) {
    combinedLeadActions.push(...goal.leadActions);
  }
}

// Optioneel: duplicaten verwijderen
const uniqueLeadActions = [...new Set(combinedLeadActions)];

return [
  {
    json: {
      leadActions: uniqueLeadActions
    }
  }
];

const leadActions = $('Get all Lead Actions').first().json.leadActions || [];
const dailyNote = $('Get Daily Note2').first().json.daily_note;

console.log('📋 Lead actions:', leadActions);

