const now = new Date();
const basePath = '={{$node["CONFIG — Edit These Values"].json["vaultRootPath"]}}';

function getWeek(date) {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  const weekNo = Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
  return `${d.getUTCFullYear()}-${String(weekNo).padStart(2, '0')}`;
}

const cycleFilePath = $('get currentCyclePath').first().json.currentCyclePath;

const currentWeek = getWeek(now).split('-')[1];
const currentYear = getWeek(now).split('-')[0];

const output = [];

output.push(
  {
    json: {
      type: 'meta',
      label: 'vision',
      path: `${basePath}/02. 12 Week Year/01. Personal Vision.md`
    }
  },
  {
    json: {
      type: 'meta',
      label: 'cycle',
      path: `${basePath}/${cycleFilePath}`
    }
  },
  {
    json: {
      type: 'meta',
      label: 'cycleMetadata',
      path: `${basePath}/02. 12 Week Year/00. Current Cycle Metadata.md`
    }
  },
  {
    json: {
      type: 'meta',
      label: 'weekly',
      path: `${basePath}/02. 12 Week Year/Week ${currentYear}-${currentWeek}.md`,
      weekNumber: currentWeek
    }
  }
);

return output;

// ============================================
// Process and Generate Weekly Plan
// ============================================
// Input: Aggregated data from Fetch All Files
// Output: weeklyPlanContent, telegramMessage, weekNumber

// --- Helper functions ---
function stripStrikethrough(text) {
  return text.replace(/~~(.+?)~~/g, '$1');
}
function isStrikethrough(text) {
  return /~~.+?~~/.test(text);
}

function getISOWeekDateRange(year, week) {
  // Calculate Monday of the given ISO week
  const jan4 = new Date(year, 0, 4);
  const dayOfWeek = jan4.getDay() || 7;
  const monday = new Date(jan4);
  monday.setDate(jan4.getDate() - dayOfWeek + 1 + (week - 1) * 7);
  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  const fmt = (d) => `${d.getDate()}-${d.getMonth() + 1}-${d.getFullYear()}`;
  return `${fmt(monday)} t/m ${fmt(sunday)}`;
}

const allItems = $('Aggregate All Results').first().json.data;
const pathsData = $('Generate All Paths').all();

const debug = {
  itemCount: allItems ? allItems.length : 0,
  pathsCount: pathsData ? pathsData.length : 0
};

// Map items by their label from the original paths
const files = {};
for (let i = 0; i < pathsData.length; i++) {
  const label = pathsData[i].json.label;
  const content = allItems[i]?.data || allItems[i]?.content || '';
  files[label] = content;
  if (label === 'weekly' && pathsData[i].json.weekNumber) {
    files.weekNumber = pathsData[i].json.weekNumber;
  }
}

// Extract current week from metadata file
let currentWeek = 1;
const weekMatch = files.cycleMetadata?.match(/Current week:\s*(\d+)/i);
if (weekMatch) {
  currentWeek = parseInt(weekMatch[1]);
}

// Parse cycle file
const cycleContent = files.cycle || '';

// Extract goal titles from "# Goals (max 3)" section
const goalsHeaderMatch = cycleContent.match(/# Goals \(max 3\)([\s\S]*?)(?=# Lead Actions|$)/i);
const goalsSection = goalsHeaderMatch ? goalsHeaderMatch[1] : '';
const goalLines = goalsSection.match(/^\d+\.\s+(.+)$/gm) || [];
const goalTitles = goalLines.map(line => line.replace(/^\d+\.\s+/, '').trim());

// Parse each goal section
const goals = [];
const goalSections = cycleContent.split(/## Goal \d+:/i).slice(1);

for (let i = 0; i < goalSections.length && i < 3; i++) {
  const section = goalSections[i];
  const title = goalTitles[i] || `Goal ${i + 1}`;

  // Extract tactics table
  const tacticsMatch = section.match(/### Tactics([\s\S]*?)(?=### Lead Actions|## Goal|# |$)/i);
  const tacticsSection = tacticsMatch ? tacticsMatch[1] : '';

  // Parse table rows - skip separators and headers robustly
  const allRows = tacticsSection.match(/^\|.+\|$/gm) || [];
  const tableRows = allRows.filter(row => {
    // Skip separator rows (|---|---|)
    if (/^\|[\s\-:|]+\|$/.test(row)) return false;
    // Skip header rows (contain "tactic" or "week" as header labels)
    const stripped = stripStrikethrough(row).toLowerCase();
    if (stripped.includes('tactic') && stripped.includes('week')) return false;
    return true;
  });

  const tacticsThisWeek = [];
  const tacticsPreviousWeeks = [];
  const tacticsRecurring = [];

  for (const row of tableRows) {
    const cells = row.split('|').map(c => c.trim()).filter(c => c);
    if (cells.length >= 2) {
      // Completion is detected by strikethrough on tactic name
      const isCompleted = isStrikethrough(cells[0]);

      // Strip strikethrough before using values
      const tacticName = stripStrikethrough(cells[0]).trim();
      const weekValue = stripStrikethrough(cells[1]).toLowerCase().trim();

      // Skip completed tactics or empty names
      if (isCompleted || !tacticName) continue;

      // Check if this tactic is for current week, previous weeks, or recurring
      if (weekValue === 'elke week') {
        tacticsRecurring.push(tacticName);
      } else {
        const weekNum = parseInt(weekValue);
        if (!isNaN(weekNum)) {
          if (weekNum === currentWeek) {
            tacticsThisWeek.push(tacticName);
          } else if (weekNum < currentWeek) {
            tacticsPreviousWeeks.push({ name: tacticName, week: weekNum });
          }
        }
      }
    }
  }

  // Extract lead actions
  const leadActionsMatch = section.match(/### Lead Actions([\s\S]*?)(?=## Goal|# |$)/i);
  const leadActionsSection = leadActionsMatch ? leadActionsMatch[1] : '';
  const leadActions = (leadActionsSection.match(/^- .+$/gm) || [])
    .map(line => line.replace(/^- /, '').trim())
    .filter(line => line.length > 0);

  goals.push({
    number: i + 1,
    title: title,
    tacticsThisWeek,
    tacticsPreviousWeeks,
    tacticsRecurring,
    leadActions
  });
}

// Generate weekly plan markdown
const now = new Date();
const currentYear = now.getFullYear();
const dateRange = getISOWeekDateRange(currentYear, currentWeek);
let content = `# Plan for week ${currentWeek} of 12 - ${dateRange} - Score 0\n\n`;

for (const goal of goals) {
  content += `## Goal ${goal.number}: ${goal.title}\n`;
  content += `### Tactics\n`;

  // Uncompleted tactics from previous weeks (with week indicator)
  for (const tactic of goal.tacticsPreviousWeeks) {
    content += `- [ ] ${tactic.name} (week ${tactic.week})\n`;
  }

  // Tactics for this week
  for (const tactic of goal.tacticsThisWeek) {
    content += `- [ ] ${tactic}\n`;
  }

  // Recurring tactics
  for (const tactic of goal.tacticsRecurring) {
    content += `- [ ] ${tactic}\n`;
  }

  if (goal.tacticsThisWeek.length === 0 && goal.tacticsRecurring.length === 0 && goal.tacticsPreviousWeeks.length === 0) {
