const data = $input.first().json;
const cycleContent = data.cycle || '';

// Split op echte newlines (Unix \n én Windows \r\n)
const lines = cycleContent.split(/\r?\n/);

const weeklyScores = [];
const goals = [];
let currentGoal = null;
let inTacticTable = false;

// --- 1. Weekly Scorecard ---
const scorecardStart = lines.findIndex(l => l.includes('# Weekly Scorecard'));
if (scorecardStart !== -1) {
  for (let i = scorecardStart + 1; i < lines.length; i++) {
    const line = lines[i];
    if (!line.trim().startsWith('|')) continue;
    if (line.match(/^[\s|:\-]+$/)) continue;
    const cells = line.split('|').map(c => c.trim()).filter(c => c);
    if (cells.length < 2) continue;
    const weekNum = parseInt(cells[0]);
    if (isNaN(weekNum) || weekNum <= 0) continue;
    const percentages = cells.slice(1)
      .map(c => { const m = c.match(/(\d+)%/); return m ? parseInt(m[1]) : null; })
      .filter(v => v !== null);
    if (percentages.length > 0) {
      const avg = Math.round(percentages.reduce((s, v) => s + v, 0) / percentages.length);
      weeklyScores.push({ week: weekNum, scores: percentages, average: avg });
    }
  }
}

// --- 2. Goals & Tactics (line-by-line) ---
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  const goalHeader = line.match(/^## Goal (\d+):\s*(.+)/);
  if (goalHeader) {
    if (currentGoal) goals.push(currentGoal);
    currentGoal = {
      num: parseInt(goalHeader[1]),
      title: goalHeader[2].trim(),
      completedTactics: 0,
      totalTactics: 0,
      completionRate: 0
    };
    inTacticTable = false;
    continue;
  }
  if (!currentGoal) continue;

  if (line.includes('### Tactics'))      { inTacticTable = true;  continue; }
  if (line.includes('### Lead Actions')) { inTacticTable = false; continue; }

  if (inTacticTable && line.trim().startsWith('|')) {
    if (line.match(/Tactic|Week/i) || line.match(/^[\s|:\-]+$/)) continue;
    const cells = line.split('|').map(c => c.trim()).filter(c => c);
    if (cells.length < 2) continue;
    const tacticCell = cells[0];
    if (!tacticCell || tacticCell.match(/^[\-:]+$/)) continue;
    currentGoal.totalTactics++;
    if (tacticCell.includes('~~')) currentGoal.completedTactics++;
  }
}
if (currentGoal) goals.push(currentGoal);
goals.forEach(g => {
  g.completionRate = g.totalTactics > 0
    ? Math.round((g.completedTactics / g.totalTactics) * 100) : 0;
});

// --- 3. Aggregates ---
const completedTactics = goals.reduce((s, g) => s + g.completedTactics, 0);
const totalTactics     = goals.reduce((s, g) => s + g.totalTactics, 0);

const overallAvg = weeklyScores.length > 0
  ? Math.round(weeklyScores.reduce((s, w) => s + w.average, 0) / weeklyScores.length) : 0;

let trend = 'stable';
if (weeklyScores.length >= 2) {
  const half = Math.ceil(weeklyScores.length / 2);
  const first = weeklyScores.slice(0, half).reduce((s, w) => s + w.average, 0) / half;
  const last  = weeklyScores.slice(-half).reduce((s, w) => s + w.average, 0) / half;
  trend = last > first + 3 ? 'improving' : last < first - 3 ? 'declining' : 'stable';
}


return [{ json: {
  ...data,
  scorecard: { weeklyScores, overallAvg, trend, weeksWithScorecard: weeklyScores.length },
  tacticStats: { completedTactics, totalTactics },
  goals
}}];

