const llmOutput = $input.first().json.text || '';
const meta = $('Build LLM Prompt').first().json.meta;
let plan;
try {
  const jsonMatch = llmOutput.match(/\{[\s\S]*\}/);
  plan = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
} catch(e) { plan = null; }

if (!plan || !plan.goals) {
  return [{ json: { preview: '\u274c Kon geen plan genereren. Controleer de LLM output.', plan: null, meta, rawOutput: llmOutput } }];
}

let preview = `\ud83d\udccb *Nieuw 12 Week Year Cycle Plan*\n`;
preview += `Week ${meta.newStartWeek}-${meta.newEndWeek} (${meta.newYear})\n\n`;
for (let i = 0; i < plan.goals.length; i++) {
  const g = plan.goals[i];
  preview += `*Goal ${i+1}: ${g.title}*\n`;
  for (const t of g.tactics) {
    preview += `  \u2022 ${t.tactic} (week ${t.week})\n`;
  }
  preview += `  _Lead:_ ${g.leadActions.join(', ')}\n\n`;
}
preview += `*Verwachte struggles:*\n`;
for (const s of plan.struggles) {
  preview += `  \u26a1 ${s.struggle} \u2192 ${s.mitigation}\n`;
}
preview += `\n*Target:* ${plan.targetExecution}%+\n`;
preview += `\n_Akkoord? Reageer met ok of geef feedback._`;

return [{ json: { preview, plan, meta } }];

const answer = $input.first().json?.body?.message?.text || $input.first().json?.body?.text || 'ok';
const prevData = $('Format Preview').first().json;
const plan = prevData.plan;
const meta = prevData.meta;

if (!plan) {
  return [{ json: { error: true, content: '', savePath: '', metadataContent: '' } }];
}

// Build cycle file from template
let content = `# Goals (max 3)\n`;
for (let i = 0; i < plan.goals.length; i++) {
  content += `${i+1}. ${plan.goals[i].title}\n`;
}

content += `\n---\n# Lead Actions\n`;
for (let i = 0; i < plan.goals.length; i++) {
  const g = plan.goals[i];
  content += `## Goal ${i+1}: ${g.title}\n`;
  content += `### Tactics\n`;
  content += `| Tactic | Week |\n`;
  content += `| ------ | ---- |\n`;
  for (const t of g.tactics) {
    content += `| ${t.tactic} | ${t.week} |\n`;
  }
  content += `### Lead Actions\n`;
  for (const a of g.leadActions) {
    content += `- ${a}\n`;
  }
  content += `\n---\n\n`;
}

content += `# Action\n`;
content += `## What Actions will you struggle with?\n`;
for (const s of plan.struggles) {
  content += `- ${s.struggle}\n`;
}
content += `\n## What will you do to overcome those struggles?\n`;
for (const s of plan.struggles) {
  content += `- ${s.mitigation}\n`;
}

content += `\n# Weekly Scorecard\n\n`;
content += `| Week | Execution | G1 Score | G2 Score | G3 Score | Notes |\n`;
content += `| ---- | --------- | -------- | -------- | -------- | ----- |\n`;
for (let w = 1; w <= 12; w++) {
  content += `| ${w}    | %         | %        | %        | %        |       |\n`;
}
content += `\n**Cumulative Execution Rate:** %  \n`;
content += `**Target:** ${plan.targetExecution}%+  \n`;
content += `**Gap:** %\n`;

const metadataContent = `cycle_file: ${meta.newCycleFileName}\nyear: ${meta.newYear}\nstart_week: ${meta.newStartWeek}\nend_week: ${meta.newEndWeek}\ncurrent_week: 1`;

return [{ json: {
  content, savePath: meta.newCycleFilePath,
  metadataContent, metadataPath: meta.metadataPath,
  userFeedback: answer
} }];

// Handle both message replies and callback queries
const body = $('Telegram Trigger1').first().json.message.text

let selectedGoal = 1;

// Check if it's a callback query (button click)
if (body.callback_query?.data) {
  const callbackData = body.callback_query.data;
  const goalMatch = callbackData.match(/goal_(\d+)/);
  selectedGoal = goalMatch ? parseInt(goalMatch[1]) : 1;
}
// Check if it's a text message reply (user typed "1", "2", or "3")
else if (body.message?.text) {
  const text = body.message.text.trim();
  const num = parseInt(text);

  if (num >= 1 && num <= 3) {
    selectedGoal = num;
  } else {
    // Invalid input, default to 1
    return [{
      json: {
        error: `Invalid goal selection: ${text}. Please choose 1, 2, or 3.`,
        selectedGoal: 1
      }
    }];
  }
}

return [{
  json: {
    selectedGoal: selectedGoal
  }
}];

// Build the updated Daily Note with 3 sections:
// 1. Week goals (Tactics from all goals)
// 2. Lead Actions (ALL lead actions)
// 3. Today's Focus (from yesterday's "Morgen")

const dailyNote = items[0].json.daily_note || '';
const goals = items[1].json.goals || [];
const tomorrowPriority = items[2].json.tomorrowPriority || '';
const selectedGoal = items[3].json.selectedGoal || 1;

// === WEEK GOALS ===
let weekGoalsText = '';
goals.forEach(goal => {
  weekGoalsText += `**${goal.number}. ${goal.title}**\n`;
  if (goal.tactics.length > 0) {
    goal.tactics.forEach(tactic => {
      weekGoalsText += `- [ ] ${tactic.tactic} (Week ${tactic.week})\n`;
    });
  }
  weekGoalsText += '\n';
});

// === LEAD ACTIONS ===
let leadActionsText = '';
goals.forEach(goal => {
  leadActionsText += `**${goal.number}. ${goal.title}**\n`;
  if (goal.leadActions.length > 0) {
    goal.leadActions.forEach(action => {
      const cleanAction = action.replace('- ', '').trim();
      leadActionsText += `- [ ] ${cleanAction}\n`;
    });
  }
  leadActionsText += '\n';
});

// === TODAY'S FOCUS ===
const todayFocusText = tomorrowPriority ? `- [ ] ${tomorrowPriority}` : '- [ ] (Set from yesterday\'s priority)';

// === UPDATE DAILY NOTE ===
let updatedNote = dailyNote;

// Update "Week goal(s)" section under "12 Week Year"
const weekGoalRegex = /- \*\*Week goal\(s\):\*\*\n((?:.*\n)*?)(?=- \*\*|###|$)/;
const weekGoalSection = `- **Week goal(s):**\n${weekGoalsText}`;
if (weekGoalRegex.test(updatedNote)) {
  updatedNote = updatedNote.replace(weekGoalRegex, weekGoalSection);
}

// Update "This week's lead actions" section
const leadActionsRegex = /- \*\*This week's lead actions:\*\*\n((?:.*\n)*?)(?=###|$)/;
const leadActionsSection = `- **This week's lead actions:**\n${leadActionsText}`;
if (leadActionsRegex.test(updatedNote)) {
  updatedNote = updatedNote.replace(leadActionsRegex, leadActionsSection);
}

// Update "Today's Focus" section
const focusRegex = /### Today's Focus\n((?:.*\n)*?)(?=###|$)/;
const focusSection = `### Today's Focus\n${todayFocusText}\n`;
if (focusRegex.test(updatedNote)) {
  updatedNote = updatedNote.replace(focusRegex, focusSection);
}

return [{
  json: {
    updated_daily_note: updatedNote,
    selectedGoal: selectedGoal
  }
}];

// Parse callback_data to determine action type
const callbackQuery = $input.first().json.callback_query || {};
const data = callbackQuery.data || '';

let action = 'unknown';
let payload = {};

if (data.startsWith('goal_select_')) {
  action = 'goal_select';
  payload.goalId = data.replace('goal_select_', '');
} else if (data.startsWith('tactic_select_')) {
  action = 'tactic_select';
  payload.tacticId = data.replace('tactic_select_', '');
} else if (data.startsWith('wr_')) {
  // NEW: Handle wr_ prefix from Weekly Review workflow
  action = 'weekly_review';
  const parts = data.split('_');
  // Format: wr_{executionId}_toggle_{type}_{goalNum}_{itemIndex}
  // OR: wr_{executionId}_confirm
  payload.executionId = parts[1];
  if (parts[2] === 'confirm') {
    payload.subAction = 'confirm';
  } else if (parts[2] === 'toggle' && parts.length >= 6) {
    payload.subAction = 'toggle';
    payload.itemType = parts[3];  // 't' for tactic, 'l' for lead action
    payload.goalNum = parseInt(parts[4]);
    payload.itemIndex = parseInt(parts[5]);
    payload.toggleKey = `${parts[3]}_${parts[4]}_${parts[5]}`; // e.g., 't_1_0'
  }
} else if (data.startsWith('weekly_review_')) {
  // Legacy format support
  action = 'weekly_review';
  const parts = data.split('_');
  if (parts.length >= 4) {
    payload.executionId = parts[2];
    if (parts[3] === 'toggle' && parts.length >= 5) {
      payload.subAction = 'toggle';
      payload.index = parseInt(parts[4]);
    } else if (parts[3] === 'confirm') {
      payload.subAction = 'confirm';
    }
  }
} else if (data.startsWith('weekly_feedback_')) {
  action = 'weekly_feedback';
  const feedbackMap = { '1': 'Teleurgesteld', '2': 'Neutraal', '3': 'Tevreden', '4': 'Trots' };
  payload.rating = data.replace('weekly_feedback_', '');
  payload.feedbackText = feedbackMap[payload.rating] || 'Onbekend';
}

return [{
  json: {
    action: action,
    payload: payload,
    rawData: data,
    callbackQueryId: callbackQuery.id,
    chatId: callbackQuery.message?.chat?.id,
    messageId: callbackQuery.message?.message_id
  }
}];

// Parse the Cycle for: Goals, Tactics (bullet points), Lead Actions per goal
const cycleContent = items[0]?.json?.cycle_content || '';

// Check if we have valid content
if (!cycleContent || cycleContent.trim() === '' || cycleContent.includes('Error') || cycleContent.includes('not found')) {
  return [{
    json: {
      goals: [],
      error: 'Weekly plan file not found or empty'
    }
  }];
}

const goals = [];

// Split content by "## Goal X:" headers
const parts = cycleContent.split(/## Goal (\d+):\s*(.+?)\n/);

// Process pairs: [before, goalNum, goalTitle, content, before, goalNum2, ...]
for (let i = 1; i < parts.length; i += 3) {
  const goalNum = parseInt(parts[i]);
  const goalTitle = parts[i + 1].trim();
  let goalContent = parts[i + 2] || '';

  // Extract Tactics (now as bullet points with checkboxes)
  let tactics = [];
  const tacticsMatch = goalContent.match(/### Tactics\n([\s\S]*?)(?=### Lead Actions|$)/);

  if (tacticsMatch) {
    const tacticsText = tacticsMatch[1];
    // Find all lines starting with "- [ ]" or "- [x]"
    const tacticLines = tacticsText
      .split('\n')
      .filter(line => line.match(/^\s*-\s*\[[xX\s]\]/));

    tactics = tacticLines.map(line => {
      // Extract checkbox status and text
      const checkboxMatch = line.match(/^\s*-\s*\[([xX\s])\]\s*(.+)/);
      if (checkboxMatch) {
        const isChecked = checkboxMatch[1].toLowerCase() === 'x';
        const tacticText = checkboxMatch[2].trim();
        return {
          tactic: tacticText,
          checked: isChecked,
          icon: isChecked ? '✅' : '📌'
        };
      }
      return null;
    }).filter(t => t !== null);
  }

  // Extract Lead Actions
  let leadActions = [];
  const leadActionsMatch = goalContent.match(/### Lead Actions\n([\s\S]*?)(?=## Goal|# |$)/);

  if (leadActionsMatch) {
    leadActions = leadActionsMatch[1]
      .split('\n')
      .filter(line => line.trim().startsWith('-'))
      .map(line => line.trim());
  }

  goals.push({
    number: goalNum,
    title: goalTitle,
    tactics: tactics,
    leadActions: leadActions
  });
}

// Return error if no goals found
if (goals.length === 0) {
  return [{
    json: {
