const tactics = $('Return selected tactics for daily note').first().json.tactics || [];

// Escape alle MarkdownV2 special characters met DUBBELE backslash
function escapeMarkdownV2(text) {
  return text
    .replace(/\\/g, '\\\\\\\\')
    .replace(/_/g, '\\\\_')
    .replace(/\*/g, '\\\\*')
    .replace(/\[/g, '\\\\[')
    .replace(/\]/g, '\\\\]')
    .replace(/\(/g, '\\\\(')
    .replace(/\)/g, '\\\\)')
    .replace(/~/g, '\\\\~')
    .replace(/`/g, '\\\\`')
    .replace(/>/g, '\\\\>')
    .replace(/#/g, '\\\\#')
    .replace(/\+/g, '\\\\+')
    .replace(/-/g, '\\\\-')
    .replace(/=/g, '\\\\=')
    .replace(/\|/g, '\\\\|')
    .replace(/\{/g, '\\\\{')
    .replace(/\}/g, '\\\\}')
    .replace(/\./g, '\\\\.')
    .replace(/!/g, '\\\\!');
}

