// Get the selected goal number and stored goals
const rawData = $('Start').first().json.rawData_split_firstItem;
const goalNumber = Number(rawData.split('_').pop());

const goalsJson = $('Fetch Stored Goals').first().json.goals || '[]';
const goals = JSON.parse(goalsJson);
// Find the selected goal
const selectedGoal = goals.find(g => g.number === goalNumber);

if (!selectedGoal) {
  return [{
    json: {
      error: 'Goal not found',
      goalNumber,
      availableGoals: goals.map(g => g.number)
    }
  }];
}

// Build tactics inline keyboard
const inlineKeyboard = selectedGoal.tactics.map(tactic => [{
  text: `${tactic.icon} ${tactic.tactic.substring(0, 40)}`,
  callback_data: `tactic_select_${tactic.id}`
}]);

// Add back button
inlineKeyboard.push([{
  text: '🔙 Terug naar goals',
  callback_data: 'back_to_goals'
}]);

// Build message text (MarkdownV2)
const escapedTitle = selectedGoal.title.replace(/[_*\[\]()~`>#+\-=|{}.!]/g, '\\$&');
let messageText = `🎯 *Goal ${goalNumber}: ${escapedTitle}*\n\n`;
messageText += `Kies een tactic om je op te focussen:\n`;

return [{
  json: {
    messageText,
    inlineKeyboard: { inline_keyboard: inlineKeyboard },
    selectedGoal,
    chatId: $('Start').first().json.chatId_firstItem,
    messageId: $('Start').first().json.messageId_firstItem,
    queryId: $('Start').first().json.callbackQueryId_firstItem
  }
}];

// Parse callback data from Telegram inline keyboard
const callback = $input.first().json.callback_query;

if (!callback) {
  return [{ json: { error: 'No callback query found' } }];
}

const callbackData = callback.data;
const messageId = callback.message.message_id;
const chatId = callback.message.chat.id;
const queryId = callback.id;

// Parse different callback types
let actionType = '';
let goalNumber = null;
let tacticId = null;
let currentGoalNumber = null;

if (callbackData.startsWith('goal_select_')) {
  actionType = 'goal_select';
  goalNumber = parseInt(callbackData.replace('goal_select_', ''));
} else if (callbackData.startsWith('tactic_select_')) {
  actionType = 'tactic_select';
  tacticId = callbackData.replace('tactic_select_', '');
  goalNumber = parseInt(tacticId.split('.')[0]);
} else if (callbackData === 'back_to_goals') {
  // back_to_goals uses the same route as other_goal
  actionType = 'other_goal';
} else if (callbackData.startsWith('more_same_goal_')) {
  actionType = 'more_same_goal';
  currentGoalNumber = parseInt(callbackData.replace('more_same_goal_', ''));
} else if (callbackData === 'other_goal') {
  actionType = 'other_goal';
} else if (callbackData === 'done_selecting') {
  actionType = 'done_selecting';
}

return [{
  json: {
    actionType,
    goalNumber,
    tacticId,
    currentGoalNumber,
    callbackData,
    messageId,
    chatId,
    queryId,
    rawCallback: callback
  }
}];

// Get data from upstream nodes
const goalsData = $('Fetch Goals for Tactic').first().json;
const callbackData = $('Parse Callback Data').first().json;

// Parse goals JSON
const goals = JSON.parse(goalsData.goals);

// Get existing selected tactics (may be null or JSON string)
let existingTactics = [];
if (goalsData.selectedTactics) {
  existingTactics = JSON.parse(goalsData.selectedTactics);
}

// Add new tactic if not already selected
const tacticId = callbackData.tacticId;
if (!existingTactics.includes(tacticId)) {
  existingTactics.push(tacticId);
}

// Build selectedTacticsDetails with full info
const selectedTacticsDetails = existingTactics.map(id => {
  // Parse tactic ID format: "goalNumber.tacticIndex" (e.g., "1.1")
  const [goalNum, tacticIdx] = id.split('.').map(Number);
  const goal = goals.find(g => g.number === goalNum);
  const tactic = goal?.tactics?.[tacticIdx - 1];

  return {
    id: id,
    name: tactic?.tactic || 'Unknown tactic',
    goalName: goal?.title || 'Unknown goal'
  };
});

// Find current tactic name
const [currentGoalNum, currentTacticIdx] = tacticId.split('.').map(Number);
const currentGoal = goals.find(g => g.number === currentGoalNum);
const currentTactic = currentGoal?.tactics?.[currentTacticIdx - 1];

return [{
  json: {
    tacticId: tacticId,
    tacticName: currentTactic?.tactic || 'Unknown tactic',
    goalNumber: callbackData.goalNumber,
    selectedTactics: JSON.stringify(existingTactics),
    selectedTacticsDetails: selectedTacticsDetails,
    chatId: callbackData.chatId,
    messageId: callbackData.messageId,
    queryId: callbackData.queryId
  }
}];

