    noTactics: false,
    message,
    keyboard: JSON.stringify({ inline_keyboard: keyboard }),
    chatId: $('Parse Callback Data').first().json.chatId,
    messageId: $('Parse Callback Data').first().json.messageId,
    queryId: $('Parse Callback Data').first().json.queryId
  }
}];

// Build goals menu showing only goals with unselected tactics
const goalsJson = $('Fetch Goals for Other').first().json.goals || '[]';
const selectedTacticsJson = $('Fetch Goals for Other').first().json.selectedTactics || '[]';

const goals = JSON.parse(goalsJson);
let selectedTactics = [];
try {
  selectedTactics = JSON.parse(selectedTacticsJson);
} catch (e) {
  selectedTactics = [];
}

// Filter goals that still have unselected tactics
const availableGoals = goals.filter(goal => {
  const unselectedTactics = goal.tactics.filter(t => !selectedTactics.includes(t.id));
  return unselectedTactics.length > 0;
});

if (availableGoals.length === 0) {
  // All tactics from all goals are selected
  return [{
    json: {
      allSelected: true,
      message: '*Alle tactics zijn al geselecteerd\\!*\n\nKlik op Klaar om je daily note bij te werken\\.',
