      messageId: $('Parse Callback Data').first().json.messageId,
      queryId: $('Parse Callback Data').first().json.queryId
    }
  }];
}

// Build inline keyboard with available goals
const keyboard = availableGoals.map(goal => {
  const unselectedCount = goal.tactics.filter(t => !selectedTactics.includes(t.id)).length;
  const displayName = `${goal.title} (${unselectedCount} beschikbaar)`;
  const truncated = displayName.length > 40 ? displayName.substring(0, 37) + '...' : displayName;
  return [{ text: truncated, callback_data: `goal_select_${goal.number}` }];
});

// Add done button
keyboard.push([{ text: '✅ Klaar met selecteren', callback_data: 'done_selecting' }]);

const selectedCount = selectedTactics.length;
const message = `🎯 *Kies een goal*\n\n_${selectedCount} tactic${selectedCount !== 1 ? 's' : ''} geselecteerd_`;

return [{
  json: {
    allSelected: false,
    message,
    keyboard: JSON.stringify({ inline_keyboard: keyboard }),
    chatId: $('Parse Callback Data').first().json.chatId,
    messageId: $('Parse Callback Data').first().json.messageId,
    queryId: $('Parse Callback Data').first().json.queryId
  }
}];

// Build final daily note entry from all selected tactics
const goalsJson = $('Fetch Goals for Done').first().json.goals || '[]';
const selectedTacticsJson = $('Fetch Goals for Done').first().json.selectedTactics || '[]';

// Get existing daily note content from Fetch Daily Note node
let existingDailyNote = $('Fetch Daily Note').first().json.daily_note || '';

const goals = JSON.parse(goalsJson);
let selectedTactics = [];
try {
  selectedTactics = JSON.parse(selectedTacticsJson);
} catch (e) {
  selectedTactics = [];
}

if (selectedTactics.length === 0) {
  return [{
    json: {
      noSelection: true,
      message: '*Geen tactics geselecteerd\\!*\n\nJe hebt nog geen tactics gekozen\\.',
      chatId: $('Parse Callback Data').first().json.chatId,
      messageId: $('Parse Callback Data').first().json.messageId,
      queryId: $('Parse Callback Data').first().json.queryId
    }
  }];
}

// Group selected tactics by goal
const goalTacticsMap = new Map();
for (const tacticId of selectedTactics) {
  for (const goal of goals) {
    for (const tactic of goal.tactics) {
      if (tactic.id === tacticId) {
        if (!goalTacticsMap.has(goal.number)) {
          goalTacticsMap.set(goal.number, {
            title: goal.title,
            tactics: [],
            leadActions: goal.leadActions || []
          });
        }
        goalTacticsMap.get(goal.number).tactics.push(tactic.tactic);
      }
    }
  }
}

// Build the new 12 Week Year section content
let newSection = '### 12 Week Year \uD83C\uDFAF\n';

// Week goals with selected tactics underneath
newSection += '- **Week goal(s):**\n';
for (const [goalNum, data] of goalTacticsMap) {
  newSection += `  - ${data.title}\n`;
  for (const tacticName of data.tactics) {
    newSection += `    - [ ] ${tacticName}\n`;
  }
}

// Lead actions from goals that have selected tactics
newSection += '- **This week\'s lead actions:**\n';
for (const [goalNum, data] of goalTacticsMap) {
  newSection += `  - ${data.title}\n`;
  for (const leadAction of data.leadActions) {
    // Lead actions already have "- [ ]" format, strip it and re-add with proper indentation
    const cleanAction = leadAction.replace(/^-\s*\[\s*\]\s*/, '').trim();
    newSection += `    - [ ] ${cleanAction}\n`;
  }
}

// Replace the 12 Week Year section in the existing daily note
// Match from '### 12 Week Year' until the next '###' section or end of file
const sectionRegex = /### 12 Week Year[^]*?(?=###|$)/;

let updatedDailyNote;
if (sectionRegex.test(existingDailyNote)) {
  // Replace existing section
  updatedDailyNote = existingDailyNote.replace(sectionRegex, newSection + '\n');
} else {
  // Append if section doesn't exist
  updatedDailyNote = existingDailyNote + '\n' + newSection;
}

// Build confirmation message for Telegram
let confirmMsg = '*\u2705 Daily note bijgewerkt\\!*\n\n';
confirmMsg += '*Geselecteerde tactics:*\n';
for (const [goalNum, data] of goalTacticsMap) {
  const escapedGoal = data.title.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&');
  for (const tacticName of data.tactics) {
    const escapedName = tacticName.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&');
    confirmMsg += `\u2022 ${escapedName} \\(${escapedGoal}\\)\n`;
  }
}
confirmMsg += '\n_Je daily note is bijgewerkt met deze focus\\._';

return [{
  json: {
    noSelection: false,
    updatedDailyNote,
    confirmMessage: confirmMsg,
    selectedCount: selectedTactics.length,
    chatId: $('Parse Callback Data').first().json.chatId,
    messageId: $('Parse Callback Data').first().json.messageId,
    queryId: $('Parse Callback Data').first().json.queryId,
    rowId: $('Fetch Goals for Done').first().json.id
  }
}];

// Build tactics menu for the selected goal (with filtering)
const goalNumber = $('Parse Callback Data').first().json.goalNumber;
const goalsJson = $('Fetch Stored Goals').first().json.goals || '[]';
const selectedTacticsJson = $('Fetch Stored Goals').first().json.selectedTactics || '[]';

const goals = JSON.parse(goalsJson);
let selectedTactics = [];
try {
  selectedTactics = JSON.parse(selectedTacticsJson);
} catch (e) {
  selectedTactics = [];
}

const goal = goals.find(g => g.number === goalNumber);

if (!goal) {
  return [{
    json: {
      error: 'Goal not found',
      chatId: $('Parse Callback Data').first().json.chatId,
      messageId: $('Parse Callback Data').first().json.messageId,
      queryId: $('Parse Callback Data').first().json.queryId
    }
  }];
}

// Filter out already selected tactics
const availableTactics = goal.tactics.filter(t => !selectedTactics.includes(t.id));

if (availableTactics.length === 0) {
  return [{
    json: {
      noTactics: true,
      message: 'Alle tactics van deze goal zijn al geselecteerd\\!',
      keyboard: JSON.stringify({
        inline_keyboard: [
          [{ text: '⬅️ Terug naar goals', callback_data: 'other_goal' }]
        ]
      }),
      chatId: $('Parse Callback Data').first().json.chatId,
      messageId: $('Parse Callback Data').first().json.messageId,
      queryId: $('Parse Callback Data').first().json.queryId
    }
  }];
}

// Build inline keyboard with available tactics
const keyboard = availableTactics.map(tactic => {
  const displayName = tactic.tactic.length > 30 
    ? tactic.tactic.substring(0, 27) + '...' 
    : tactic.tactic;
  return [{ text: displayName, callback_data: `tactic_select_${tactic.id}` }];
});

// Add back button
keyboard.push([{ text: '⬅️ Terug naar goals', callback_data: 'other_goal' }]);

const escapedGoalName = goal.title.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&');
const selectedCount = selectedTactics.length;
let message = `🎯 *${escapedGoalName}*\n\nKies een tactic:`;
if (selectedCount > 0) {
  message = `🎯 *${escapedGoalName}*\n_${selectedCount} tactic${selectedCount !== 1 ? 's' : ''} al geselecteerd_\n\nKies een tactic:`;
}

return [{
  json: {
    noTactics: false,
    message,
    keyboard: JSON.stringify({ inline_keyboard: keyboard }),
    chatId: $('Parse Callback Data').first().json.chatId,
    messageId: $('Parse Callback Data').first().json.messageId,
    queryId: $('Parse Callback Data').first().json.queryId
  }
}];

// Parse the Cycle for: Goals, Tactics (bullet points), Lead Actions per goal
const cycleContent = items[0]?.json?.cycle_content || '';

// Check if we have valid content
if (!cycleContent || cycleContent.trim() === '' || cycleContent.includes('Error') || cycleContent.includes('not found')) {
  return [{
    json: {
      goals: [],
      error: 'Weekly plan file not found or empty'
    }
  }];
}

const goals = [];

// Split content by "## Goal X:" headers
const parts = cycleContent.split(/## Goal (\d+):\s*(.+?)\n/);

// Process pairs: [before, goalNum, goalTitle, content, before, goalNum2, ...]
for (let i = 1; i < parts.length; i += 3) {
  const goalNum = parseInt(parts[i]);
  const goalTitle = parts[i + 1].trim();
  let goalContent = parts[i + 2] || '';

  // Extract Tactics (now as bullet points with checkboxes)
  let tactics = [];
  const tacticsMatch = goalContent.match(/### Tactics\n([\s\S]*?)(?=### Lead Actions|$)/);

  if (tacticsMatch) {
    const tacticsText = tacticsMatch[1];
    // Find all lines starting with "- [ ]" or "- [x]"
    const tacticLines = tacticsText
      .split('\n')
      .filter(line => line.match(/^\s*-\s*\[[xX\s]\]/));

    tactics = tacticLines.map(line => {
      // Extract checkbox status and text
      const checkboxMatch = line.match(/^\s*-\s*\[([xX\s])\]\s*(.+)/);
      if (checkboxMatch) {
        const isChecked = checkboxMatch[1].toLowerCase() === 'x';
        const tacticText = checkboxMatch[2].trim();
        return {
          tactic: tacticText,
          checked: isChecked,
          icon: isChecked ? '✅' : '📌'
        };
      }
      return null;
    }).filter(t => t !== null);
  }

  // Extract Lead Actions
  let leadActions = [];
  const leadActionsMatch = goalContent.match(/### Lead Actions\n([\s\S]*?)(?=## Goal|# |$)/);

  if (leadActionsMatch) {
    leadActions = leadActionsMatch[1]
      .split('\n')
      .filter(line => line.trim().startsWith('-'))
      .map(line => line.trim());
  }

  goals.push({
    number: goalNum,
    title: goalTitle,
    tactics: tactics,
    leadActions: leadActions
  });
}

// Return error if no goals found
if (goals.length === 0) {
  return [{
    json: {
      goals: [],
      error: 'No goals found in weekly plan'
    }
  }];
}

return [{
  json: {
    goals: goals
  }
}];

// Add tactic IDs to goals (1.1, 1.2, 2.1, 2.2, etc)
// Also pass through tomorrowPriority from yesterday's note
const goalsData = $input.first().json || {};
const goals = goalsData.goals || [];
const error = goalsData.error || null;
const tomorrowPriority = items[2]?.json?.tomorrowPriority || '';

// Pass through error if present
if (error || !goals || !Array.isArray(goals) || goals.length === 0) {
  return [{
    json: {
      goals: [],
      tomorrowPriority: tomorrowPriority,
      error: error || 'No goals found',
      totalGoals: 0,
      totalTactics: 0
    }
  }];
}

// Add IDs to tactics
const goalsWithIds = goals.map(goal => {
  return {
    ...goal,
    tactics: (goal.tactics || []).map((tactic, index) => {
      const tacticNum = index + 1;
      const fullId = `${goal.number}.${tacticNum}`;

      return {
        ...tactic,
        id: fullId
      };
    })
  };
});

return [{
  json: {
    goals: goalsWithIds,
    tomorrowPriority: tomorrowPriority,
    totalGoals: goalsWithIds.length,
    totalTactics: goalsWithIds.reduce((sum, g) => sum + (g.tactics?.length || 0), 0)
  }
}];

// Get the selected tactic IDs from the first node
const selectedTacticIds = $('Fetch Goals for Tactic').first().json.selectedTactics;

// Get the full goals data from the second node
const goalsData = $('Add Tactic IDs (1.1, 1.2, etc)1').first().json;

// Initialize array to store matched tactics
const matchedTactics = [];

// Iterate through each goal and its tactics
goalsData.goals.forEach(goal => {
  goal.tactics.forEach(tactic => {
    // Check if this tactic's ID is in the selected list
    if (selectedTacticIds.includes(tactic.id)) {
      // Add simple string format: "ID - Tactic text"
      matchedTactics.push(`${tactic.id} - ${tactic.tactic}`);
    }
  });
});

// Return as single item with array of strings
return [{ json: { tactics: matchedTactics } }];

const tactics = $('Code in JavaScript').first().json.tactics || [];
const dailyNote = $('Fetch Daily Note for Tactic').first().json.daily_note;

console.log('📋 Tactics:', tactics);

let updated = dailyNote;

// Format tactics
const tacticsFormatted = tactics
  .map(tactic => '   - [ ] ' + tactic)
  .join('\n');

console.log('📝 Formatted tactics:', JSON.stringify(tacticsFormatted));

// Zoek en vervang de Week tactic(s) sectie
const tacticSearch = "- **Week tactic(s):**\n  -";

if (updated.includes(tacticSearch)) {
  // Vervang de lege bullet met de gevormatteerde tactics
  updated = updated.replace(tacticSearch, "- **Week tactic(s):**\n" + tacticsFormatted);
  console.log('✅ Week tactics bijgewerkt');
} else {
  console.log('⚠️ Week tactic(s) sectie niet gevonden');
}

return [{ json: { updatedDailyNote: updated } }];

const tactics = $('Code in JavaScript').first().json.tactics || [];

// Escape alle MarkdownV2 special characters met DUBBELE backslash
function escapeMarkdownV2(text) {
  return text
    .replace(/\\/g, '\\\\\\\\')
    .replace(/_/g, '\\\\_')
    .replace(/\*/g, '\\\\*')
    .replace(/\[/g, '\\\\[')
    .replace(/\]/g, '\\\\]')
    .replace(/\(/g, '\\\\(')
    .replace(/\)/g, '\\\\)')
    .replace(/~/g, '\\\\~')
    .replace(/`/g, '\\\\`')
    .replace(/>/g, '\\\\>')
    .replace(/#/g, '\\\\#')
    .replace(/\+/g, '\\\\+')
    .replace(/-/g, '\\\\-')
    .replace(/=/g, '\\\\=')
    .replace(/\|/g, '\\\\|')
    .replace(/\{/g, '\\\\{')
    .replace(/\}/g, '\\\\}')
    .replace(/\./g, '\\\\.')
    .replace(/!/g, '\\\\!');
}

// Format tactics als array of comma-separated string
let tacticsList;
if (Array.isArray(tactics)) {
  tacticsList = tactics;
} else {
  tacticsList = tactics.split(',').map(t => t.trim()).filter(t => t.length > 0);
}

// Maak lijst met bullets
const formattedTactics = tacticsList
  .map(tactic => `• ${escapeMarkdownV2(tactic)}`)
  .join('\\n');

// Complete message  
const text = `✅ Dit zijn de gekozen tactics:\\n\\n${formattedTactics}`;

return [{ json: { text } }];

// Toggle the selected state and rebuild the message
const handleData = $('Handle Weekly Review Callback').first().json;
const originalMessage = $('Start').first().json._firstItem;
const callbackQuery = originalMessage.callback_query || {};
const message = callbackQuery.message || {};

// Get current inline keyboard
const currentKeyboard = message.reply_markup?.inline_keyboard || [];

// Build the match suffix for the new format: _{type}_{goalNum}_{itemIndex}
const matchSuffix = handleData.itemType && handleData.goalNum !== undefined && handleData.itemIndex !== undefined
  ? `_${handleData.itemType}_${handleData.goalNum}_${handleData.itemIndex}`
  : `_toggle_${handleData.index}`; // Fallback to old format

// Toggle the state in the keyboard
const newKeyboard = currentKeyboard.map(row => {
  return row.map(button => {
    // Check if this is the toggled button
    // New format: wr_{execId}_toggle_{type}_{goalNum}_{itemIndex}
    if (button.callback_data?.endsWith(matchSuffix)) {
      // Toggle between checked and unchecked
      // Weekly Review uses ⬜ (U+2B1C) for unchecked
      const isCurrentlyChecked = button.text.startsWith('\u2611') || button.text.startsWith('\u2705') || button.text.startsWith('☑') || button.text.startsWith('✅');
      // Remove any leading checkbox emoji
      const itemText = button.text.replace(/^[\u2B1C\u2610\u2611\u2705⬜☐☑✅] /, '');
      return {
        text: (isCurrentlyChecked ? '\u2B1C ' : '\u2611 ') + itemText,  // ⬜ unchecked, ☑ checked
        callback_data: button.callback_data
      };
    }
    return button;
  });
});

return [{
  json: {
    chat_id: handleData.chatId,
    message_id: handleData.messageId,
    reply_markup: { inline_keyboard: newKeyboard }
  }
}];

// Handle weekly_review callbacks from AM - Week - Review workflow
const originalMessage = $('Start').first().json._firstItem;
const callbackQuery = originalMessage.callback_query || {};
const data = callbackQuery.data || '';
const parsedData = $('Start').first().json.Parse_Callback_Data__firstItem;

// Get execution ID from parsed data
const executionId = parsedData.payload?.executionId || '';

// Parse weekly_review callback
const isToggle = parsedData.payload?.subAction === 'toggle';
const isConfirm = parsedData.payload?.subAction === 'confirm';

const result = {
  chatId: callbackQuery.message?.chat?.id || '',
  messageId: callbackQuery.message?.message_id || '',
  callbackQueryId: callbackQuery.id || '',
  callbackData: data,
  executionId: executionId
};

if (isToggle) {
  result.type = 'toggle';
  // Support both old format (index only) and new format (itemType, goalNum, itemIndex)
  result.index = parsedData.payload?.index;
  result.itemType = parsedData.payload?.itemType;  // 't' or 'l'
  result.goalNum = parsedData.payload?.goalNum;
  result.itemIndex = parsedData.payload?.itemIndex;
  result.toggleKey = parsedData.payload?.toggleKey;
} else if (isConfirm) {
  result.type = 'confirm';
} else {
  result.type = 'unknown';
}

return [{ json: result }];

// Parse which items are selected from the inline keyboard
const handleData = $('Handle Weekly Review Callback').first().json;
const originalMessage = $('Start').first().json._firstItem;
const callbackQuery = originalMessage.callback_query || {};
const message = callbackQuery.message || {};

// Get current inline keyboard
const currentKeyboard = message.reply_markup?.inline_keyboard || [];

// Find selected items (buttons with checkmark)
const toggledItems = [];
currentKeyboard.forEach(row => {
  row.forEach(button => {
    const isChecked = button.text.startsWith('\u2611') || button.text.startsWith('\u2705') || button.text.startsWith('\u2705') || button.text.startsWith('\u2611');
    if (isChecked && button.callback_data) {
      // New format: wr_{execId}_toggle_{type}_{goalNum}_{itemIndex}
      const newMatch = button.callback_data.match(/wr_[^_]+_toggle_([tl])_(\d+)_(\d+)/);
      if (newMatch) {
        toggledItems.push(`${newMatch[1]}_${newMatch[2]}_${newMatch[3]}`);
        return;
      }
      // Old format: weekly_review_{execId}_toggle_{index}
      const oldMatch = button.callback_data.match(/weekly_review_[^_]+_toggle_(\d+)/);
      if (oldMatch) {
        toggledItems.push(oldMatch[1]);
      }
    }
  });
});

return [{
  json: {
    chatId: handleData.chatId,
    messageId: handleData.messageId,
    executionId: handleData.executionId,
    toggledItems: toggledItems,
    body: {
      toggledItems: toggledItems,
      confirmed: true
    }
  }
}];

// Prepare feedback data
const data = $input.first().json;
const now = new Date();

const d = new Date(Date.UTC(now.getFullYear(), now.getMonth(), now.getDate()));
d.setUTCDate(d.getUTCDate() + 4 - (d.getUTCDay() || 7));
const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
const weekNo = Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
const weekNumber = `${d.getUTCFullYear()}-${String(weekNo).padStart(2, '0')}`;

const feedbackEmoji = { '1': '😔', '2': '😐', '3': '😊', '4': '😍' };
const emoji = feedbackEmoji[data.payload.rating] || '';

return [{
  json: {
    ...data,
    weekNumber: weekNumber,
    feedbackLine: `\n\n## Persoonlijke Reflectie\n\n${emoji} ${data.payload.feedbackText}\n\n_Toegevoegd: ${now.toISOString()}_`,
    weeklyFilePath: `={{$node["CONFIG — Edit These Values"].json["vaultRootPath"]}}/03. Reflecties/01. Weekly reflection/${weekNumber}.md`
  }
}];

// Append feedback to weekly file content
const currentContent = $input.first().json.content || '';
const feedbackData = $('Handle Weekly Feedback').first().json;

// Check if feedback section already exists
let updatedContent;
if (currentContent.includes('## Persoonlijke Reflectie')) {
  // Replace existing feedback
  updatedContent = currentContent.replace(
    /## Persoonlijke Reflectie[\s\S]*?(?=\n## |$)/,
    feedbackData.feedbackLine.trim() + '\n\n'
  );
} else {
  // Append new feedback
  updatedContent = currentContent + feedbackData.feedbackLine;
}

return [{
  json: {
    path: feedbackData.weeklyFilePath,
    content: updatedContent,
    chatId: feedbackData.chatId,
    messageId: feedbackData.messageId,
    feedbackText: feedbackData.payload.feedbackText
  }
}];

const reflectionQuestion = $('Start').first().json.message_reply_to_message_text_firstItem;
const userAnswer = $('Start').first().json.message_text_firstItem;
let dailyNote = $input.first().json.daily_note;

// Strip "Reflectie: " prefix
const cleanReflection = reflectionQuestion.replace(/^Reflectie:\s*/i, '').trim();

console.log('🔍 Zoeken naar:', cleanReflection);

// Helper functie: strip markdown opmaak en normaliseer
function normalizeText(text) {
  return text
    .replace(/\*\*(.+?)\*\*/g, '$1')  // **bold** → bold
    .replace(/\*(.+?)\*/g, '$1')        // *italic* → italic
    .replace(/_(.+?)_/g, '$1')            // _italic_ → italic
    .replace(/`(.+?)`/g, '$1')            // `code` → code
    .replace(/\s+/g, ' ')                // multiple spaces → single space
    .trim()
    .toLowerCase();
}

const normalizedQuestion = normalizeText(cleanReflection);
console.log('📝 Genormaliseerde vraag:', normalizedQuestion);

// Vind de EXACTE regel in daily_note met "- [ ]"
const lines = dailyNote.split('\n');
let foundIndex = -1;

for (let i = 0; i < lines.length; i++) {
  if (lines[i].includes(`- [ ]`)) {
    // Normaliseer de regel zonder de checkbox syntax
    const lineWithoutCheckbox = lines[i].replace(/^\s*-\s*\[\s*\]\s*/, '').trim();
    const normalizedLine = normalizeText(lineWithoutCheckbox);

    console.log(`🔎 Regel ${i}: "${normalizedLine}"`);

    // Check voor match (exact of partial)
    if (normalizedLine === normalizedQuestion || 
        normalizedLine.includes(normalizedQuestion) ||
        normalizedQuestion.includes(normalizedLine)) {
      foundIndex = i;
      console.log('✅ Gevonden op regel', i, ':', lines[i]);
      break;
    }
  }
}

if (foundIndex !== -1) {
  // Vink af: [ ] → [x]
  lines[foundIndex] = lines[foundIndex].replace(/- \[ \]/, '- [x]');

  // Voeg antwoord toe op volgende regel (geïndentered)
  lines.splice(foundIndex + 1, 0, `  ${userAnswer}`);

  dailyNote = lines.join('\n');
  console.log('✅ Update geslaagd!');
} else {
  console.log('❌ Reflectie niet gevonden in daily_note');
  console.log('💡 Gezochte vraag:', normalizedQuestion);
  console.log('💡 Beschikbare vragen:');
  lines.forEach((line, i) => {
    if (line.includes('- [ ]')) {
      const normalized = normalizeText(line.replace(/^\s*-\s*\[\s*\]\s*/, ''));
      console.log(`   ${i}: ${normalized}`);
    }
  });
}

return [{ json: { updatedDailyNote: dailyNote } }];

let content = $input.first().json.daily_note;
const commitment = $('Start').first().json.message_text_firstItem;

if (!content || content.trim().length === 0) {
  return [
    {
      json: {
        daily_note_content: content,
        modified: false,
        reason: "Daily note does not exist"
      }
    }
  ];
}

/* =========================
   DATE RESOLUTION (HEADER)
   ========================= */

const today = DateTime.now().setZone('Europe/Amsterdam');
const todayStr = today.toFormat('yyyy-MM-dd');
const yesterdayStr = today.minus({ days: 1 }).toFormat('yyyy-MM-dd');
const tomorrowStr = today.plus({ days: 1 }).toFormat('yyyy-MM-dd');

// Replace Obsidian / Templater placeholders
content = content
  .replace(/{{date:YYYY-MM-DD}}/g, todayStr)
  .replace(/<% tp\.date\.now\("YYYY-MM-DD", -1\) %>/g, yesterdayStr)
  .replace(/<% tp\.date\.now\("YYYY-MM-DD", \+1\) %>/g, tomorrowStr);

/* =========================
   TODAY'S FOCUS LOGIC
   ========================= */

const focusSectionRegex =
  /### Today's Focus[\s\S]*?(?=\n### |\n## |\Z)/;

const commitmentLine = `- [ ] ${commitment}`;
let modifiedContent = content;

const match = content.match(focusSectionRegex);

if (match) {
  let focusSection = match[0];

  // Remove template placeholders
  focusSection = focusSection
    .replace(/- \[ \] {{focus_task1}}\n?/g, "")
    .replace(/- \[ \] {{focus_task2}}\n?/g, "")
    .replace(/- \[ \] {{focus_task3}}\n?/g, "");

  // Remove identical commitment (idempotency)
  focusSection = focusSection.replace(
    new RegExp(
      `- \\[ \\] ${commitment.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\n?`,
      "g"
    ),
    ""
  );

  const lines = focusSection.trim().split("\n");
  const header = lines.shift(); // ### Today's Focus
  const remainingTasks = lines.filter(l => l.trim().startsWith("- [ ]"));

  const newFocusSection = [
    header,
    commitmentLine,
    ...remainingTasks
  ].join("\n");

  modifiedContent = content.replace(match[0], newFocusSection);
}

return [
  {
    json: {
      daily_note_content: modifiedContent,
      modified: true
    }
  }
];

const content = $('Check Daily Note File1').first().json.daily_note;
const commitment = $('Start').first().json.message_text_firstItem;

if (!content || content.trim().length === 0) {
  // File does not exist or is empty — creation handled elsewhere
  return [
    {
      json: {
        daily_note_content: content,
        modified: false,
        reason: "Daily note does not exist"
      }
    }
  ];
}

// Regex to find the Today's Focus section
const focusSectionRegex =
  /### Today's Focus[\s\S]*?(?=\n### |\n## |\Z)/;

const commitmentLine = `- [ ] ${commitment}`;
let modifiedContent = content;

const match = content.match(focusSectionRegex);

if (match) {
  let focusSection = match[0];

  // Remove placeholder lines if present
  focusSection = focusSection
    .replace(/- \[ \] {{focus_task1}}\n?/g, "")
    .replace(/- \[ \] {{focus_task2}}\n?/g, "")
    .replace(/- \[ \] {{focus_task3}}\n?/g, "");

  // Remove existing identical commitment (idempotency)
  focusSection = focusSection.replace(
    new RegExp(`- \\[ \\] ${commitment.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\n?`, "g"),
    ""
  );

  // Split section into lines
  const lines = focusSection.trim().split("\n");

  // Rebuild: header + commitment + remaining tasks
  const header = lines.shift(); // "### Today's Focus"
  const remainingTasks = lines.filter(line => line.trim().startsWith("- [ ]"));

  const newFocusSection =
    [
      header,
      commitmentLine,
      ...remainingTasks
    ].join("\n");

  modifiedContent = content.replace(match[0], newFocusSection);
}

return [
  {
    json: {
      daily_note_content: modifiedContent,
      modified: true
    }
  }
];

// Extract executionId and message text for struggles webhook
const stateRow = $('Start').first().json._firstItem;
const userMessage = $('Start').first().json.message_firstItem?.text || '';
const chatId = $('Start').first().json.message_firstItem?.chat?.id || '';

return [{
  json: {
    executionId: stateRow.executionId,
    messageText: userMessage,
    chatId: chatId,
    rowId: stateRow.id  // For deleting the row later
  }
}];

